import{_ as i,o as a,c as s,a2 as e}from"./chunks/framework.y1bVONfd.js";const c=JSON.parse('{"title":"Multimedia Support","description":"Handle audio, image, and video content through wr-proxy","frontmatter":{"title":"Multimedia Support","description":"Handle audio, image, and video content through wr-proxy"},"headers":[],"relativePath":"guide/multimedia.md","filePath":"guide/multimedia.md"}'),n={name:"guide/multimedia.md"};function o(l,t,r,d,h,p){return a(),s("div",null,[...t[0]||(t[0]=[e(`<h1 id="multimedia-support" tabindex="-1">Multimedia Support <a class="header-anchor" href="#multimedia-support" aria-label="Permalink to &quot;Multimedia Support&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>wr-proxy provides first-class support for multimedia API endpoints — audio synthesis, speech transcription, image generation, and image editing — all routed through the same unified gateway with automatic failover and provider selection.</p><h2 id="supported-endpoints" tabindex="-1">Supported Endpoints <a class="header-anchor" href="#supported-endpoints" aria-label="Permalink to &quot;Supported Endpoints&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Endpoint</th><th>Method</th><th>Content Type</th><th>Description</th></tr></thead><tbody><tr><td><code>/v1/audio/speech</code></td><td>POST</td><td>JSON → Binary Audio</td><td>Text-to-speech synthesis</td></tr><tr><td><code>/v1/audio/transcriptions</code></td><td>POST</td><td>Multipart → JSON</td><td>Speech-to-text transcription</td></tr><tr><td><code>/v1/images/generations</code></td><td>POST</td><td>JSON → JSON</td><td>Image generation (DALL·E, etc.)</td></tr><tr><td><code>/v1/images/edits</code></td><td>POST</td><td>Multipart → JSON</td><td>Image editing</td></tr><tr><td><code>/v1/images/variations</code></td><td>POST</td><td>Multipart → JSON</td><td>Image variations</td></tr></tbody></table><h2 id="how-binary-content-is-handled" tabindex="-1">How Binary Content Is Handled <a class="header-anchor" href="#how-binary-content-is-handled" aria-label="Permalink to &quot;How Binary Content Is Handled&quot;">​</a></h2><p>Multimedia endpoints use a dedicated fast path (<code>handleBinaryProxy</code>) that differs from the standard chat completions flow:</p><ol><li><strong>Authentication</strong> — same token-based auth as chat endpoints</li><li><strong>Model extraction</strong> — parsed from JSON body or multipart form field</li><li><strong>Provider selection</strong> — uses the same router with health-aware selection</li><li><strong>Binary passthrough</strong> — response body is streamed directly without JSON parsing</li></ol><h3 id="what-s-skipped" tabindex="-1">What&#39;s Skipped <a class="header-anchor" href="#what-s-skipped" aria-label="Permalink to &quot;What&#39;s Skipped&quot;">​</a></h3><p>The binary proxy intentionally skips these steps (not applicable to binary content):</p><ul><li>Complexity assessment (no text to analyze)</li><li>Desensitization (no PII in audio/image bytes)</li><li>Request sanitization (format is endpoint-specific)</li><li>Knowledge capture (binary content not capturable)</li></ul><h3 id="what-s-preserved" tabindex="-1">What&#39;s Preserved <a class="header-anchor" href="#what-s-preserved" aria-label="Permalink to &quot;What&#39;s Preserved&quot;">​</a></h3><ul><li>Token authentication and model whitelist checks</li><li>Provider health-aware selection with failover</li><li>Cooldown mechanism (quota exhaustion, rate limiting)</li><li>Request logging and cost metering</li><li>Response Content-Type passthrough</li></ul><h2 id="audio-speech-tts" tabindex="-1">Audio Speech (TTS) <a class="header-anchor" href="#audio-speech-tts" aria-label="Permalink to &quot;Audio Speech (TTS)&quot;">​</a></h2><p>Convert text to speech using any TTS model available through your providers.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://localhost:5051/v1/audio/speech</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Authorization: Bearer &lt;token&gt;&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Content-Type: application/json&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;{</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;model&quot;: &quot;tts-1&quot;,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;input&quot;: &quot;Hello, welcome to WebRouter!&quot;,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;voice&quot;: &quot;alloy&quot;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  }&#39;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --output</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> speech.mp3</span></span></code></pre></div><h2 id="audio-transcription-stt" tabindex="-1">Audio Transcription (STT) <a class="header-anchor" href="#audio-transcription-stt" aria-label="Permalink to &quot;Audio Transcription (STT)&quot;">​</a></h2><p>Transcribe audio files to text. Supports multipart form upload.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://localhost:5051/v1/audio/transcriptions</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Authorization: Bearer &lt;token&gt;&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -F</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;file=@recording.mp3&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -F</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;model=whisper-1&quot;</span></span></code></pre></div><h2 id="image-generation" tabindex="-1">Image Generation <a class="header-anchor" href="#image-generation" aria-label="Permalink to &quot;Image Generation&quot;">​</a></h2><p>Generate images through any OpenAI-compatible provider.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://localhost:5051/v1/images/generations</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Authorization: Bearer &lt;token&gt;&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Content-Type: application/json&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;{</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;model&quot;: &quot;dall-e-3&quot;,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;prompt&quot;: &quot;A serene mountain lake at sunset&quot;,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;n&quot;: 1,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;size&quot;: &quot;1024x1024&quot;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  }&#39;</span></span></code></pre></div><h2 id="provider-compatibility" tabindex="-1">Provider Compatibility <a class="header-anchor" href="#provider-compatibility" aria-label="Permalink to &quot;Provider Compatibility&quot;">​</a></h2><p>Any provider that offers OpenAI-compatible endpoints for these operations is supported. Common providers:</p><table tabindex="0"><thead><tr><th>Provider</th><th>TTS</th><th>STT</th><th>Image Gen</th></tr></thead><tbody><tr><td>OpenAI</td><td>tts-1, tts-1-hd</td><td>whisper-1</td><td>dall-e-3</td></tr><tr><td>Azure OpenAI</td><td>Yes</td><td>Yes</td><td>Yes</td></tr><tr><td>Custom (OpenAI-compatible)</td><td>Yes</td><td>Yes</td><td>Yes</td></tr></tbody></table><h2 id="failover-behavior" tabindex="-1">Failover Behavior <a class="header-anchor" href="#failover-behavior" aria-label="Permalink to &quot;Failover Behavior&quot;">​</a></h2><p>Multimedia requests follow the same failover logic as chat requests:</p><ol><li>If the selected provider fails, wr-proxy tries the next healthy provider with the same model</li><li>Rate-limited providers enter cooldown (configurable duration)</li><li>Quota-exhausted providers are cooled for 30 minutes</li><li>Configurable via <code>max_failover</code> and <code>max_retry_count</code> settings</li></ol>`,28)])])}const k=i(n,[["render",o]]);export{c as __pageData,k as default};
